={
  "messaging_product": "whatsapp",
  "to": "{{ 
  (() => {
    let phone = String($('Intervalo entre mensagens1').item.json.whatsapp|| "").replace(/\D/g, "");

    // Remove prefixo internacional com 00, ex: 005511989342471
    if (phone.startsWith("00")) {
      phone = phone.slice(2);
    }

    // Se vier com 0 antes do DDD, ex: 011989342471
    if (phone.startsWith("0") && phone.length >= 11) {
      phone = phone.slice(1);
    }

    // Se já vier com 55, mantém
    if (phone.startsWith("55")) {
      return phone;
    }

    // Se vier DDD + número celular, ex: 11989342471
    if (phone.length === 11) {
      return "55" + phone;
    }

    // Se vier DDD + número com 8 dígitos, adiciona o 9
    // Ex: 1189342471 vira 5511989342471
    if (phone.length === 10) {
      return "55" + phone.slice(0, 2) + "9" + phone.slice(2);
    }

    return phone;
  })()
}}",
  "type": "template",
  "template": {
    "name": "mensagem_1_sem_incorporadora",
    "language": { "code": "pt_BR" },
    "components": [
      {
        "type": "body",
        "parameters": {{ JSON.stringify([
  { "type": "text", "text": String($('Intervalo entre mensagens1').item.json.clientes || "") }
]) }}
      }
    ]
  }
}

